// ── STAGE 0: Initialize all pipeline state ──────────────────────────────
// Accepts: { prompt: string }
// Returns: full pipeline state object

const body = $input.item.json.body || $input.item.json;

if (!body.prompt || typeof body.prompt !== 'string' || body.prompt.trim() === '') {
  throw new Error('Missing or empty required field: prompt. Send POST { "prompt": "your idea" }');
}

const rowId = 'ROW-' + Date.now();
const timestamp = new Date().toISOString();

return {
  json: {
    rowId:        rowId,
    timestamp:    timestamp,
    prompt:       body.prompt.trim(),

    // Stage 1 output
    gptIdea:      '',

    // Stage 2 output (Gemini-formatted version)
    geminiFormatted: '',

    // Stage 3 — critique loop state (max 3 cycles)
    cycleCount:   0,
    critique1:    '',
    critique2:    '',
    critique3:    '',
    approved:     false,
    finalConcept: '',

    // Stage 4 output
    researchSummary: '',
    sources:         '',
    notes:           '',

    // Overall tracking
    status:       'Processing',
    sheetsRowNum: 0
  }
};

