// ── STAGE 1 PARSE: Extract idea from GPT-4o Mini response ───────────────
const pipeline = $('Initialize Pipeline').item.json;
const gptRaw   = $input.item.json;

let ideaText = '';
try {
  const content = gptRaw.choices[0].message.content.trim();
  // Try to parse as JSON (GPT was instructed to return JSON)
  const parsed = JSON.parse(content);
  ideaText = [
    '**Core Idea:** '          + (parsed.core_idea          || ''),
    '**Target Market:** '      + (parsed.target_market      || ''),
    '**Value Proposition:** '  + (parsed.value_proposition  || ''),
    '**Revenue Model:** '      + (parsed.revenue_model      || ''),
    '**Implementation:** '     + (parsed.implementation_steps ? parsed.implementation_steps.join(' → ') : '')
  ].join('\n');
} catch (e) {
  // Fallback: use raw text if JSON parse fails
  ideaText = gptRaw.choices[0].message.content.trim();
}

if (!ideaText) throw new Error('GPT-4o Mini returned an empty response.');

return {
  json: {
    ...pipeline,
    gptIdea: ideaText
  }
};

