// ── STAGE 2 PARSE: Extract structured data from Gemini response ──────────
const pipeline  = $('Parse GPT Response').item.json;
const geminiRaw = $input.item.json;

let geminiFormatted = pipeline.gptIdea; // fallback to GPT idea if Gemini fails

try {
  const content = geminiRaw.candidates[0].content.parts[0].text.trim();
  const parsed  = JSON.parse(content);
  geminiFormatted = [
    parsed.formatted_concept || pipeline.gptIdea,
    parsed.category   ? '[Category: '   + parsed.category   + ']' : '',
    parsed.complexity ? '[Complexity: '  + parsed.complexity  + ']' : '',
    parsed.confidence_score !== undefined ? '[Confidence: ' + (parsed.confidence_score * 100).toFixed(0) + '%]' : ''
  ].filter(Boolean).join(' ');
} catch (e) {
  // Gemini didn't return valid JSON — use the raw text
  try {
    geminiFormatted = geminiRaw.candidates[0].content.parts[0].text.trim() || pipeline.gptIdea;
  } catch (_) {
    geminiFormatted = pipeline.gptIdea;
  }
}

return {
  json: {
    ...pipeline,
    geminiFormatted: geminiFormatted
  }
};

// ── RESTORE: Google Sheets append doesn't pass pipeline data forward ──────
// Re-attach all pipeline state so the loop has everything it needs.
const pipeline = $('Parse Gemini Response').item.json;
const sheetsResult = $input.item.json;

// Google Sheets append returns the row number via 'row_number' or from range
let sheetsRowNum = 0;
if (sheetsResult.row_number) {
  sheetsRowNum = sheetsResult.row_number;
} else if (sheetsResult.updatedRange) {
  // Parse row from range like 'Pipeline!A5:M5'
  const match = sheetsResult.updatedRange.match(/(\d+)/);
  if (match) sheetsRowNum = parseInt(match[1]);
}

return {
  json: {
    ...pipeline,
    sheetsRowNum: sheetsRowNum
  }
};

// ── LOOP GATE: Increment cycle counter ───────────────────────────────────
// This node is the loop-back target from the IF node's FALSE branch.
// On first pass it receives data from Restore Pipeline State (cycleCount=0).
// On subsequent passes it receives data from IF node (cycleCount=1,2).

const data = $input.item.json;

return {
  json: {
    ...data,
    cycleCount: (data.cycleCount || 0) + 1
  }
};

// ── CLAUDE PREP: Assemble the critique prompt with full context ───────────
const d = $input.item.json;

// Collect any prior critiques for context
const priorCritiques = [];
if (d.critique1) priorCritiques.push('Cycle 1 Critique: ' + d.critique1);
if (d.critique2) priorCritiques.push('Cycle 2 Critique: ' + d.critique2);
if (d.critique3) priorCritiques.push('Cycle 3 Critique: ' + d.critique3);

const priorContext = priorCritiques.length > 0
  ? '\n\nPREVIOUS CRITIQUE CYCLES:\n' + priorCritiques.join('\n\n')
  : '';

const systemPrompt = `You are a rigorous business concept evaluator. Your role is to critique a business idea and either APPROVE it (if it is viable, differentiated, and executable) or REQUEST ITERATION with specific improvements needed. You are on critique cycle ${d.cycleCount} of a maximum of 3 cycles. ${d.cycleCount >= 3 ? 'THIS IS THE FINAL CYCLE — you MUST make a final approval decision regardless of remaining concerns. Identify the best version of this concept and approve it.' : 'If the concept needs work, be specific about what must change.'}

Respond ONLY with a valid JSON object (no markdown, no code fences):
{
  "approved": true or false,
  "critique": "Your detailed critique (2-4 sentences). What works, what doesn't, what must change.",
  "final_concept": "The refined/approved concept statement (2-3 sentences). Incorporate improvements from prior cycles.",
  "key_risks": ["risk1", "risk2"],
  "approval_reason": "Why you are approving OR why it still needs work"
}`;

const userPrompt = `Original Business Prompt: "${d.prompt}"

GPT-4o Mini Generated Idea:\n${d.gptIdea}

Gemini-Formatted Concept:\n${d.geminiFormatted}${priorContext}`;

return {
  json: {
    ...d,
    claudeSystemPrompt: systemPrompt,
    claudeUserPrompt:   userPrompt
  }
};

