// ── STAGE 3 PARSE: Extract Claude's decision and update state ────────────
const data       = $('Critique Loop - Increment Cycle').item.json;
const claudeRaw  = $input.item.json;

let approved     = false;
let critique     = '';
let finalConcept = data.finalConcept || data.gptIdea;

try {
  const content = claudeRaw.content[0].text.trim();
  // Strip any accidental markdown fences
  const cleaned = content.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  const parsed  = JSON.parse(cleaned);

  approved     = parsed.approved === true;
  critique     = [
    parsed.critique || '',
    parsed.key_risks && parsed.key_risks.length ? 'Key Risks: ' + parsed.key_risks.join(', ') : '',
    parsed.approval_reason ? 'Decision Reason: ' + parsed.approval_reason : ''
  ].filter(Boolean).join(' | ');
  finalConcept = parsed.final_concept || finalConcept;

} catch (e) {
  // Fallback: treat raw text as critique, no approval
  try {
    critique = claudeRaw.content[0].text.trim();
  } catch (_) {
    critique = 'Claude response parse error on cycle ' + data.cycleCount;
  }
  // Force approval on cycle 3 even if parse fails (pipeline must not hang)
  approved = data.cycleCount >= 3;
}

// Store critique in the correct cycle slot
const critiqueKey = 'critique' + data.cycleCount;

return {
  json: {
    ...data,
    [critiqueKey]: critique,
    approved:      approved,
    finalConcept:  finalConcept
  }
};

