// ── STAGE 4 PARSE: Extract research data from Perplexity Sonar ───────────
const pipeline       = $('IF - Exit Loop').item.json;
const perplexityRaw  = $input.item.json;

let researchSummary = 'Research unavailable';
let sources         = '';
let notes           = '';

try {
  const content = perplexityRaw.choices[0].message.content.trim();
  const cleaned = content.replace(/^```json\s*/i, '').replace(/```\s*$/, '').trim();
  const parsed  = JSON.parse(cleaned);

  researchSummary = [
    parsed.research_summary || '',
    parsed.market_size    ? 'Market Size: '        + parsed.market_size    : '',
    parsed.market_trends  ? 'Trends: '             + parsed.market_trends  : ''
  ].filter(Boolean).join(' | ');

  sources = [
    parsed.key_competitors && parsed.key_competitors.length
      ? 'Competitors: ' + parsed.key_competitors.join(', ')
      : '',
    parsed.sources && parsed.sources.length
      ? parsed.sources.join(', ')
      : ''
  ].filter(Boolean).join(' | ');

  notes = parsed.viability_verdict ? 'Viability: ' + parsed.viability_verdict : '';

} catch (e) {
  // Fallback: use raw response text
  try {
    researchSummary = perplexityRaw.choices[0].message.content.trim();
  } catch (_) {
    researchSummary = 'Parse error — check raw Perplexity response';
  }
}

return {
  json: {
    ...pipeline,
    researchSummary: researchSummary,
    sources:         sources,
    notes:           notes,
    status:          'Completed'
  }
};

